def category_report(records):
    """Return (category, count, total) triples, highest total first.

    Ties break alphabetically by category for a stable order. Returns an
    empty list when ``records`` is empty.
    """
    totals = {}
    counts = {}
    for r in records:
        totals[r["category"]] = totals.get(r["category"], 0.0) + r["distance"]
        counts[r["category"]] = counts.get(r["category"], 0) + 1
    ranked = sorted(totals.items(), key=lambda kv: (-kv[1], kv[0]))
    return [(category, counts[category], total) for category, total in ranked]

